INSERT INTO `ai_books` VALUES (1,'深度学习','Ian Goodfellow, Yoshua Bengio, Aaron Courville','深度学习领域的奠基性著作，由三位图灵奖得主联合撰写。全书系统阐述了深度学习的基本原理和核心技术，从数学基础、机器学习基础到深度前馈网络、正则化、优化算法、卷积网络、序列建模等全面覆盖。本书既是入门者的必读教材，也是从业者的重要参考书，被全球数百所高校采用为教科书。','deep-learning','https://www.deeplearningbook.org',4.8,'','deep-learning-goodfellow','深度学习 - Ian Goodfellow 经典教材','深度学习领域奠基性著作，由 Goodfellow、Bengio、Courville 三位图灵奖得主撰写，系统阐述深度学习基本原理与核心技术。','[\"深度学习\", \"Ian Goodfellow\", \"神经网络\", \"AI教材\", \"机器学习\", \"Yoshua Bengio\"]','2026-06-05 00:00:00.000'),(2,'动手学深度学习','Aston Zhang, 李沐, Zachary C. Lipton, Alexander J. Smola','一本注重实践操作的深度学习教材，由亚马逊首席科学家李沐等人编写。全书采用交互式 Jupyter Notebook 讲解，所有概念都配有可运行的代码实现，支持 PyTorch、TensorFlow 和 MXNet 三种框架。内容涵盖线性神经网络、多层感知机、深度学习计算、卷积神经网络、现代 RNN、注意力机制、优化算法、计算性能、计算机视觉、自然语言处理等。','deep-learning','https://d2l.ai',4.7,'','dive-into-deep-learning','动手学深度学习 - 李沐 交互式教材','由李沐等人编写的交互式深度学习教材，所有概念配可运行代码，支持 PyTorch/TensorFlow/MXNet，注重实践操作的经典教程。','[\"动手学深度学习\", \"李沐\", \"PyTorch\", \"TensorFlow\", \"d2l\", \"交互式学习\"]','2026-06-05 00:00:00.000'),(3,'统计学习方法','李航','全面系统介绍统计学习方法的经典中文教材，由华为诺亚方舟实验室主任李航撰写。全书从监督学习出发，系统讲解感知机、k近邻法、朴素贝叶斯法、决策树、逻辑斯谛回归、支持向量机、提升方法、EM 算法、隐马尔可夫模型和条件随机场等核心算法。第二版新增了深度学习和强化学习的内容，是机器学习入门必读。','machine-learning','https://book.douban.com/subject/33437381/',4.6,'','statistical-learning-methods','统计学习方法 - 李航 机器学习经典','李航撰写的经典机器学习教材，系统讲解监督学习核心算法，是中文世界最具影响力的机器学习入门书籍之一。','[\"统计学习方法\", \"李航\", \"机器学习\", \"监督学习\", \"SVM\", \"中文教材\"]','2026-06-05 00:00:00.000'),(4,'机器学习','周志华','中国机器学习领域最经典的教材之一，由南京大学周志华教授（西瓜书作者）撰写。全书以清晰的逻辑和丰富的示例讲解机器学习的基本概念和方法，涵盖模型评估与选择、线性模型、决策树、神经网络、支持向量机、贝叶斯分类器、集成学习、聚类、降维与度量学习、特征选择与稀疏学习、计算学习理论、半监督学习、概率图模型和强化学习等。','machine-learning','https://book.douban.com/subject/26708119/',4.7,'','machine-learning-zhouzhihua','机器学习 - 周志华 西瓜书','周志华教授撰写的机器学习经典教材，以清晰逻辑和丰富示例讲解核心算法，是中国最具影响力的机器学习入门书。','[\"机器学习\", \"周志华\", \"西瓜书\", \"人工智能\", \"集成学习\", \"中文教材\"]','2026-06-05 00:00:00.000'),(5,'Pattern Recognition and Machine Learning','Christopher M. Bishop','模式识别与机器学习领域的权威著作，采用贝叶斯视角系统讲解机器学习核心理论。全书以概率论为基础，从概率分布、线性回归和分类模型出发，逐步深入到核方法、稀疏核机、图模型、混合模型与EM算法、近似推断、采样方法、连续潜变量模型和组合模型等高级主题。数学推导严谨，是研究生阶段机器学习理论的必读教材。','machine-learning','https://www.microsoft.com/en-us/research/people/cmbishop/prml-book/',4.7,'','prml-bishop','Pattern Recognition and Machine Learning - Bishop 经典','Bishop 的 PRML 是机器学习领域权威著作，以贝叶斯视角系统讲解核心理论，是研究生阶段必读教材。','[\"PRML\", \"Bishop\", \"模式识别\", \"贝叶斯\", \"机器学习理论\", \"概率图模型\"]','2026-06-05 00:00:00.000'),(6,'Natural Language Processing with Transformers','Lewis Tunstall, Leandro von Werra, Thomas Wolf','由 Hugging Face 团队撰写的 Transformer 和 NLP 实战指南。全书以 Hugging Face 生态为核心，全面讲解 Transformer 架构原理、文本分类、命名实体识别、文本生成、摘要、问答系统、翻译等 NLP 任务。还涵盖模型微调、蒸馏、量化等高效部署技术，是 NLP 工程实践的必备参考书。','nlp','https://transformersbook.com',4.6,'','nlp-with-transformers','Natural Language Processing with Transformers - Hugging Face 实战','Hugging Face 团队撰写的 Transformer 实战指南，全面讲解文本分类、生成、问答等 NLP 任务与模型部署技术。','[\"Transformers\", \"NLP\", \"Hugging Face\", \"文本生成\", \"BERT\", \"GPT\"]','2026-06-05 00:00:00.000'),(7,'Designing Machine Learning Systems','Chip Huyen','斯坦福大学机器学习系统设计课程的核心教材，由 Chip Huyen 撰写。全书聚焦于生产环境中 ML 系统的设计与运维，涵盖数据工程、特征工程、模型训练与评估、部署、监控、持续学习等完整 MLOps 生命周期。书中包含大量业界最佳实践和真实案例分析，是 ML 工程师从原型到生产的必备指南。','mlops','https://www.oreilly.com/library/view/designing-machine-learning/9781098107956/',4.7,'','designing-ml-systems','Designing Machine Learning Systems - Chip Huyen MLOps 实战','Chip Huyen 撰写的 ML 系统设计教材，覆盖数据工程到持续学习的完整 MLOps 生命周期，是 ML 工程化必备指南。','[\"MLOps\", \"Chip Huyen\", \"ML系统设计\", \"生产部署\", \"数据工程\", \"模型监控\"]','2026-06-05 00:00:00.000'),(8,'Building LLM Applications','Valentina Alto','一本面向开发者的 LLM 应用构建实战指南，系统讲解从提示工程到 RAG 架构、代理系统和微调的完整技术栈。全书以 LangChain、LlamaIndex 等主流框架为工具，通过丰富的代码示例演示如何构建智能问答系统、文档分析工具和对话助手等实际应用，帮助开发者快速掌握 LLM 应用开发的核心技能。','llm','https://www.packtpub.com/product/building-llm-applications/9781835462317',4.3,'','building-llm-applications','Building LLM Applications - LLM 应用构建实战','面向开发者的 LLM 应用构建指南，涵盖提示工程、RAG、代理系统和微调等完整技术栈，通过实例教你构建智能应用。','[\"LLM\", \"RAG\", \"LangChain\", \"应用开发\", \"提示工程\", \"AI代理\"]','2026-06-05 00:00:00.000'),(9,'AI Engineering','Chip Huyen','Chip Huyen 继 ML 系统设计之后的又一力作，聚焦于基础模型时代构建 AI 应用的工程实践。全书深入讲解模型评估、检索增强生成、代理系统、提示工程、微调技术、推理优化和评估框架等前沿主题，帮助工程师在大模型时代掌握从原型构建到生产部署的完整方法论，是 AI 工程化的权威指南。','llm','https://www.oreilly.com/library/view/ai-engineering/9781098166304/',4.8,'','ai-engineering-chip-huyen','AI Engineering - Chip Huyen 大模型工程实践','Chip Huyen 最新力作，深入讲解基础模型时代的 AI 工程实践，涵盖 RAG、代理、微调和推理优化等前沿主题。','[\"AI Engineering\", \"Chip Huyen\", \"大模型\", \"RAG\", \"代理系统\", \"微调\"]','2026-06-05 00:00:00.000'),(10,'大规模语言模型：从理论到实践','张奇, 桂韬, 黄萱菁','复旦大学团队编写的大语言模型系统性著作，全面介绍 LLM 的基础理论、训练技术和应用实践。内容涵盖 Transformer 架构详解、预训练技术、指令微调、人类反馈强化学习（RLHF）、高效参数微调、推理优化和模型评估等。书中还包含中文 LLM 特有的挑战与解决方案，是国内大模型领域的权威教材。','llm','https://book.douban.com/subject/36524807/',4.5,'','large-language-models-theory-practice','大规模语言模型：从理论到实践 - 复旦团队','复旦大学团队编写的 LLM 系统性著作，全面介绍预训练、微调、RLHF 等核心技术，是中文大模型领域权威教材。','[\"大语言模型\", \"LLM\", \"复旦大学\", \"预训练\", \"RLHF\", \"中文NLP\"]','2026-06-05 00:00:00.000'),(11,'强化学习（第二版）','Richard S. Sutton, Andrew G. Barto','强化学习领域的圣经级著作，由强化学习之父 Sutton 和 Barto 撰写。全书系统讲解多臂赌博机、有限和无限马尔可夫决策过程、动态规划、蒙特卡洛方法、时序差分学习、n步自举法、基于函数逼近的预测与控制、策略梯度方法等核心内容。第二版新增了深度强化学习相关章节，是理解 AlphaGo、ChatGPT RLHF 等前沿技术的理论基础。','machine-learning','https://book.douban.com/subject/34809689/',4.8,'','reinforcement-learning-sutton','强化学习 - Sutton & Barto 圣经级教材','Sutton 和 Barto 的强化学习经典著作，系统讲解 MDP、TD学习、策略梯度等核心理论，是 RL 领域必读书籍。','[\"强化学习\", \"Sutton\", \"Barto\", \"RL\", \"策略梯度\", \"MDP\"]','2026-06-05 00:00:00.000'),(12,'Generative Deep Learning','David Foster','聚焦于生成式模型的深度学习实战指南，系统讲解变分自编码器（VAE）、生成对抗网络（GAN）、自回归模型、标准化流、能量模型和扩散模型等前沿生成技术。全书使用 Keras 和 TensorFlow 实现，通过丰富的可视化示例展示从图像生成到文本生成的完整流程，是生成式 AI 领域的优秀入门书。','generative-ai','https://www.oreilly.com/library/view/generative-deep-learning/9781098134174/',4.5,'','generative-deep-learning','Generative Deep Learning - 生成式 AI 实战','David Foster 的生成式 AI 实战指南，系统讲解 VAE、GAN、扩散模型等生成技术，通过代码实现从图像到文本的生成。','[\"生成式AI\", \"GAN\", \"VAE\", \"扩散模型\", \"图像生成\", \"Keras\"]','2026-06-05 00:00:00.000'),(13,'人工智能伦理','Mark Coeckelbergh','系统探讨 AI 伦理问题的入门著作，全面分析人工智能在隐私、公平、责任、透明度和人机关系等方面的伦理挑战。书中涵盖算法偏见、自主武器、就业影响、数据隐私等关键议题，并提出建设性的伦理框架和政策建议。在 AI 快速发展的时代，理解 AI 伦理已成为技术人员和决策者的必修课。','ai-ethics','https://mitpress.mit.edu/9780262538190/ai-ethics/',4.2,'','ai-ethics-coeckelbergh','人工智能伦理 - Mark Coeckelbergh MIT 出版','系统探讨 AI 伦理问题的入门著作，分析算法偏见、隐私、公平等关键议题，是理解 AI 伦理的必修读物。','[\"AI伦理\", \"算法偏见\", \"隐私\", \"AI公平\", \"人工智能伦理\", \"技术伦理\"]','2026-06-05 00:00:00.000'),(14,'百面机器学习','诸葛越, 葫芦娃','机器学习面试与进阶的实战宝典，由 Hulu 算法团队撰写。全书以问答形式组织内容，涵盖特征工程、模型评估、经典算法（SVM、逻辑回归、决策树、K-means 等）、深度学习（CNN、RNN、GAN）、强化学习、概率图模型和工程实践等核心领域。每个问题配有详细的分析和推导过程，是 ML 面试准备的黄金资料。','machine-learning','https://book.douban.com/subject/30244418/',4.4,'','hundred-faces-ml','百面机器学习 - ML 面试与进阶宝典','Hulu 算法团队撰写的 ML 面试实战宝典，以问答形式覆盖特征工程、经典算法和深度学习，是面试准备的黄金资料。','[\"百面机器学习\", \"面试\", \"ML面试\", \"算法\", \"深度学习\", \"特征工程\"]','2026-06-05 00:00:00.000'),(15,'大模型应用开发极简入门','Olivier Caelen, Marie-Alice Blete','面向零基础读者的 GPT 和 LLM 应用开发入门指南，通过循序渐进的方式讲解如何构建基于大语言模型的应用程序。内容涵盖提示工程基础、API 调用与集成、RAG 架构设计、LangChain 框架使用、模型微调入门、成本优化和安全防护等。全书代码示例丰富，使用 Python 编写，适合想快速上手的开发者。','llm','https://www.oreilly.com/library/view/developing-apps-with/9781098152482/',4.3,'','llm-app-quick-start','大模型应用开发极简入门 - GPT 开发指南','面向零基础读者的 LLM 应用开发入门书，循序渐进讲解提示工程、RAG、LangChain 使用和模型微调，适合快速上手。','[\"LLM应用\", \"GPT\", \"LangChain\", \"RAG\", \"入门指南\", \"Python\"]','2026-06-05 00:00:00.000');
