INSERT INTO `ai_tools` VALUES (1,'Cursor','Cursor 是一款基于 VSCode 的 AI 原生代码编辑器，集成了 GPT-4、Claude 等先进大模型，支持整文件编辑、多文件上下文理解、内联代码生成和智能调试。它通过独特的 Cursor Tab 预测性补全和对整个代码库的语义搜索，大幅提升开发效率，是目前最受欢迎的 AI 编程工具之一。','ide','Freemium, Pro $20/mo','https://cursor.sh','[\"基于整个代码库的语义搜索与上下文理解\", \"Cursor Tab 智能预测性代码补全\", \"多模型支持，包括 GPT-4o、Claude 3.5 Sonnet\", \"内联代码编辑与多文件重构\", \"自然语言指令直接生成代码\", \"终端内 AI 辅助调试\"]','','cursor-ai-ide','Cursor AI 编辑器 - 基于 VSCode 的智能编程工具','Cursor 是一款 AI 原生的代码编辑器，集成 GPT-4 和 Claude 等大模型，支持智能代码补全、多文件编辑和语义搜索，显著提升开发效率。','[\"Cursor\", \"AI代码编辑器\", \"智能编程\", \"AI IDE\", \"代码补全\", \"GPT-4\"]','2026-06-05 00:00:00.000'),(2,'GitHub Copilot','GitHub Copilot 是由 GitHub 和 OpenAI 联合推出的 AI 编程助手，能够根据上下文自动生成代码建议。它深度集成到 VSCode、JetBrains 等主流 IDE 中，支持函数级代码生成、测试用例编写和代码解释。Copilot Chat 功能让开发者可以通过对话方式与 AI 交互，实现更灵活的编程辅助。','code-assistant','Individual $10/mo, Business $19/mo','https://github.com/features/copilot','[\"实时上下文感知的代码自动补全\", \"Copilot Chat 对话式编程辅助\", \"支持 VSCode、JetBrains、Neovim 等主流 IDE\", \"自动生成单元测试与文档注释\", \"代码审查与安全漏洞检测\", \"多语言支持，覆盖主流编程语言\"]','','github-copilot','GitHub Copilot - AI 结对编程助手','GitHub Copilot 是由 GitHub 和 OpenAI 联合推出的 AI 编程助手，支持代码自动补全、对话式编程和代码审查，深度集成主流 IDE。','[\"GitHub Copilot\", \"AI编程助手\", \"代码生成\", \"OpenAI\", \"Copilot Chat\", \"自动补全\"]','2026-06-05 00:00:00.000'),(3,'Claude Code','Claude Code 是 Anthropic 推出的命令行 AI 编码代理工具，能够直接在终端中理解整个代码库、执行复杂的多文件重构、运行 bash 命令和自动化工作流。它采用代理式架构，可自主规划任务、搜索代码、编辑文件并通过 git 管理变更，是目前最强大的终端 AI 编程代理之一。','code-assistant','Pay-as-you-go via Anthropic API','https://claude.ai/code','[\"终端内完整的代码库理解与操作\", \"多文件重构与跨文件编辑\", \"自动化 bash 命令执行与调试\", \"Git 工作流集成，自动提交与分支管理\", \"MCP 协议支持，可扩展工具生态\", \"代理式自主规划与任务分解\"]','','claude-code','Claude Code - Anthropic 命令行 AI 编程代理','Claude Code 是 Anthropic 推出的命令行 AI 编码代理，支持终端内代码库理解、多文件重构和自动化工作流，是目前最强大的终端编程代理工具。','[\"Claude Code\", \"Anthropic\", \"AI编程代理\", \"命令行工具\", \"代码重构\", \"MCP协议\"]','2026-06-05 00:00:00.000'),(4,'Windsurf','Windsurf（原名 Codeium）是一款 AI 驱动的代码编辑器，由 Codeium 团队开发。它内置了强大的 AI 流（AI Flows）功能，能够理解开发者的工作意图，提供上下文感知的代码建议。Windsurf 支持全文件编辑、多文件操作和智能代码重构，是 Cursor 的主要竞争对手。','ide','Freemium, Pro $15/mo','https://codeium.com/windsurf','[\"AI Flows 上下文感知的代码编辑流\", \"Cascade 多文件智能编辑引擎\", \"全代码库索引与语义搜索\", \"自然语言指令驱动开发\", \"实时代码补全与错误检测\", \"支持 VSCode 扩展生态\"]','','windsurf-ai-editor','Windsurf - AI 原生代码编辑器 | Codeium','Windsurf 是 Codeium 推出的 AI 原生代码编辑器，支持 AI Flows 智能编辑流和多文件操作，是下一代 AI 编程体验的代表。','[\"Windsurf\", \"Codeium\", \"AI编辑器\", \"AI Flows\", \"代码补全\", \"智能编程\"]','2026-06-05 00:00:00.000'),(5,'v0 by Vercel','v0 是 Vercel 推出的生成式 UI 设计工具，能够通过自然语言描述直接生成 React 前端界面代码。它结合了 Vercel 的前端生态优势，生成的代码基于 Tailwind CSS 和 shadcn/ui 组件库，可直接复制到项目中使用。v0 支持从文字描述、截图和设计稿生成界面，是前端开发的革命性工具。','design','Freemium, Pro $20/mo','https://v0.dev','[\"自然语言描述生成 React UI 组件\", \"基于 Tailwind CSS 和 shadcn/ui\", \"截图转代码功能\", \"实时预览与迭代编辑\", \"一键复制代码到项目中\", \"支持响应式布局自动生成\"]','','v0-by-vercel','v0 by Vercel - 生成式 UI 设计工具','v0 是 Vercel 推出的生成式 UI 工具，通过自然语言描述自动生成 React 前端代码，支持 Tailwind CSS 和 shadcn/ui 组件库。','[\"v0\", \"Vercel\", \"UI生成\", \"React\", \"Tailwind CSS\", \"shadcn/ui\", \"前端开发\"]','2026-06-05 00:00:00.000'),(6,'Bolt.new','Bolt.new 是 StackBlitz 推出的基于浏览器的全栈 AI 开发平台，用户可以通过自然语言描述需求，直接在浏览器中生成、编辑和部署完整的 Web 应用。它内置了完整的开发环境，支持 Node.js、React、Vue 等框架，无需任何本地配置即可快速搭建项目原型。','code-assistant','Freemium, Pro $20/mo','https://bolt.new','[\"浏览器内自然语言生成全栈应用\", \"一键部署到生产环境\", \"内置完整开发环境和包管理\", \"支持 React、Vue、Node.js 等主流框架\", \"实时预览与即时修改\", \"与 GitHub 集成，可导出完整项目\"]','','bolt-new','Bolt.new - 浏览器内 AI 全栈开发平台','Bolt.new 是 StackBlitz 推出的浏览器内全栈 AI 开发平台，支持自然语言生成和部署 Web 应用，无需本地环境配置。','[\"Bolt.new\", \"StackBlitz\", \"全栈开发\", \"AI编程\", \"浏览器开发\", \"Web应用\"]','2026-06-05 00:00:00.000'),(7,'Replit Agent','Replit Agent 是 Replit 推出的 AI 开发代理，集成在 Replit 在线 IDE 中。它能够理解自然语言需求，自主规划项目结构、编写代码、安装依赖、调试错误并部署应用。Replit Agent 的目标是让任何人都能通过对话创建软件，大幅降低编程门槛。','agent-framework','Freemium, Core $25/mo','https://replit.com/agent','[\"自然语言驱动的应用构建\", \"自动项目结构规划与依赖管理\", \"交互式调试与错误修复\", \"一键部署与托管\", \"协作式开发环境\", \"支持 Python、JavaScript、Node.js 等\"]','','replit-agent','Replit Agent - AI 驱动的在线开发代理','Replit Agent 是 Replit 推出的 AI 开发代理，支持自然语言构建应用、自动调试和一键部署，让任何人都能轻松创建软件。','[\"Replit Agent\", \"Replit\", \"AI代理\", \"在线IDE\", \"自动编程\", \"应用部署\"]','2026-06-05 00:00:00.000'),(8,'Perplexity AI','Perplexity AI 是一款 AI 驱动的搜索引擎，能够实时检索互联网信息并提供带引用来源的综合答案。它结合了大型语言模型的理解能力和实时搜索的强大功能，支持深度研究、PDF 分析、图片搜索等多种功能，是传统搜索引擎的强力替代品。','research','Freemium, Pro $20/mo','https://www.perplexity.ai','[\"实时互联网搜索并带引用来源\", \"Pro Search 深度研究模式\", \"文件上传与 PDF 分析\", \"多模型选择，包括 GPT-4、Claude 3.5\", \"组织化的收藏与搜索空间\", \"图片搜索与知识卡片\"]','','perplexity-ai','Perplexity AI - AI 驱动的智能搜索引擎','Perplexity AI 是 AI 驱动的搜索引擎，结合 LLM 和实时搜索能力，提供带引用来源的综合答案，支持深度研究和文件分析。','[\"Perplexity AI\", \"AI搜索\", \"智能搜索\", \"实时搜索\", \"深度研究\", \"知识引擎\"]','2026-06-05 00:00:00.000'),(9,'Notion AI','Notion AI 是嵌入在 Notion 工作空间中的 AI 助手，能够帮助用户写作、编辑、总结、翻译和头脑风暴。它深度集成到 Notion 的文档、数据库和知识库系统中，可以在任何页面中调用 AI 能力，提升知识管理和团队协作效率。','productivity','Add-on $10/mo per member','https://www.notion.so/product/ai','[\"文档内 AI 写作与编辑辅助\", \"会议笔记自动总结\", \"数据库内容智能分析与提取\", \"多语言翻译与改写\", \"头脑风暴与创意生成\", \"知识库智能问答\"]','','notion-ai','Notion AI - 工作空间内置 AI 助手','Notion AI 是 Notion 工作空间中内置的 AI 助手，支持写作、总结、翻译和数据库分析，全面提升知识管理和协作效率。','[\"Notion AI\", \"AI写作\", \"知识管理\", \"协作工具\", \"文档AI\", \"智能助手\"]','2026-06-05 00:00:00.000'),(10,'Midjourney','Midjourney 是目前最受欢迎的 AI 图像生成工具之一，通过文本描述即可生成高质量的艺术图像。它运行在 Discord 平台上，用户通过自然语言提示词控制图像风格、构图和细节。Midjourney 以其卓越的艺术质感和美学表现力著称，广泛用于创意设计、概念艺术和品牌视觉创作。','design','Basic $10/mo, Standard $30/mo','https://www.midjourney.com','[\"文本到图像的高质量生成\", \"丰富的艺术风格控制参数\", \"图像变体生成与迭代优化\", \"参考图混合与风格迁移\", \"高分辨率输出支持\", \"Discord 社区协作与分享\"]','','midjourney','Midjourney - AI 艺术图像生成工具','Midjourney 是领先的 AI 图像生成工具，通过文本描述生成高质量艺术图像，广泛用于创意设计和品牌视觉创作。','[\"Midjourney\", \"AI绘画\", \"图像生成\", \"艺术创作\", \"文本到图像\", \"创意设计\"]','2026-06-05 00:00:00.000'),(11,'Stable Diffusion','Stable Diffusion 是 Stability AI 发布的开源 AI 图像生成模型，用户可以通过文本描述生成逼真的图像。与闭源方案不同，Stable Diffusion 完全开源，可以在本地部署运行，支持自定义训练和微调。它拥有庞大的社区生态，ControlNet、LoRA 等扩展技术让图像生成更加精准可控。','design','Free & Open Source','https://stability.ai/stable-diffusion','[\"完全开源，可本地部署运行\", \"文本到图像和图像到图像生成\", \"ControlNet 精准构图控制\", \"LoRA 轻量级模型微调\", \"SDXL 高分辨率生成能力\", \"活跃的开源社区与模型生态\"]','','stable-diffusion','Stable Diffusion - 开源 AI 图像生成模型','Stable Diffusion 是 Stability AI 发布的开源图像生成模型，支持本地部署、自定义训练和社区扩展，提供精准可控的图像生成能力。','[\"Stable Diffusion\", \"Stability AI\", \"开源AI\", \"图像生成\", \"ControlNet\", \"LoRA\"]','2026-06-05 00:00:00.000'),(12,'Runway','Runway 是一个面向创意专业人士的 AI 视频编辑和生成平台，提供 30 多种 AI 魔法工具，涵盖视频生成、背景移除、运动跟踪、风格转换等功能。其 Gen-3 Alpha 模型能够从文本直接生成高质量视频片段，是 AI 视频生成领域的领先产品，广泛应用于电影制作、广告和社交媒体内容创作。','design','Free Plan, Standard $15/mo, Pro $35/mo','https://runwayml.com','[\"Gen-3 Alpha 文本到视频生成\", \"30+ AI 视频编辑魔法工具\", \"绿幕背景一键移除与替换\", \"运动跟踪与对象移除\", \"风格转换与色彩调整\", \"实时协作与云端渲染\"]','','runway','Runway - AI 视频生成与编辑平台','Runway 是面向创意专业人士的 AI 视频编辑平台，提供文本生成视频、背景移除、运动跟踪等功能，是 AI 视频创作的领先工具。','[\"Runway\", \"AI视频\", \"视频生成\", \"Gen-3\", \"视频编辑\", \"创意工具\"]','2026-06-05 00:00:00.000'),(13,'LangChain','LangChain 是目前最流行的 LLM 应用开发框架，提供了一套完整的工具和抽象来构建基于大语言模型的应用。它支持模型的链式调用、工具集成、提示词管理、记忆系统和代理式推理。LangChain 拥有 Python 和 JavaScript 双语言 SDK，生态丰富，是 LLM 应用开发的事实标准。','agent-framework','Free & Open Source, LangSmith from $39/mo','https://www.langchain.com','[\"LLM 链式调用与工作流编排\", \"丰富的工具和 API 集成生态\", \"提示词模板管理与优化\", \"会话记忆与上下文管理\", \"代理式推理与自主决策\", \"Python 和 JavaScript 双语言支持\"]','','langchain','LangChain - LLM 应用开发框架','LangChain 是最流行的 LLM 应用开发框架，提供链式调用、代理推理和工具集成等能力，是构建大语言模型应用的事实标准。','[\"LangChain\", \"LLM框架\", \"AI开发\", \"代理推理\", \"链式调用\", \"提示词管理\"]','2026-06-05 00:00:00.000'),(14,'LlamaIndex','LlamaIndex（原名 GPT Index）是一个专为 LLM 应用设计的数据框架，它提供了从数据接入、索引构建到查询引擎的完整工具链。LlamaIndex 擅长构建 RAG（检索增强生成）应用，支持 160 多种数据源连接器，能够将结构化、非结构化数据转化为 LLM 可理解的格式，是实现知识库问答和数据驱动 AI 应用的核心工具。','agent-framework','Free & Open Source, LlamaCloud from $99/mo','https://www.llamaindex.ai','[\"RAG 检索增强生成应用框架\", \"160+ 数据源连接器\", \"多种索引策略与查询引擎\", \"文档解析与分块处理\", \"智能路由与查询优化\", \"企业级数据处理与安全\"]','','llamaindex','LlamaIndex - LLM 数据框架与 RAG 引擎','LlamaIndex 是专为 LLM 应用设计的数据框架，提供从数据接入到查询引擎的完整工具链，是构建 RAG 应用的核心工具。','[\"LlamaIndex\", \"RAG\", \"数据框架\", \"LLM\", \"知识库\", \"检索增强生成\"]','2026-06-05 00:00:00.000'),(15,'CrewAI','CrewAI 是一个专注于多 AI 代理协作的开源框架，允许开发者定义具不同角色和专业能力的 AI 代理团队，让它们协同完成复杂任务。每个代理可以拥有独立的工具、记忆和推理能力，通过结构化的团队协作流程，实现任务分解、分工执行和结果整合，适用于研究分析、内容创作和自动化工作流等场景。','agent-framework','Free & Open Source, Enterprise Custom','https://www.crewai.com','[\"多 AI 代理角色定义与分工\", \"结构化团队协作流程编排\", \"代理间通信与结果整合\", \"任务自动分解与分配\", \"支持自定义工具集成\", \"回调和事件驱动的执行监控\"]','','crewai','CrewAI - 多 AI 代理协作框架','CrewAI 是多 AI 代理协作的开源框架，支持定义代理团队角色并协同完成复杂任务，实现任务分解和智能分工。','[\"CrewAI\", \"多代理\", \"AI协作\", \"代理框架\", \"任务自动化\", \"团队AI\"]','2026-06-05 00:00:00.000'),(16,'AutoGPT','AutoGPT 是开源 AI 代理的先驱项目，它让 GPT-4 能够自主设定目标、规划任务、使用工具并迭代执行。AutoGPT 引入了自主代理的关键概念：长期记忆、互联网访问、代码执行和持续自我改进。虽然早期版本受限于模型能力，但它开创了自主 AI 代理这一全新范式，推动了整个 Agent 生态的发展。','agent-framework','Free & Open Source','https://agpt.co','[\"自主目标设定与任务规划\", \"互联网搜索与信息获取\", \"代码生成与自动执行\", \"长期记忆与上下文管理\", \"插件系统与工具扩展\", \"持续自我迭代与改进\"]','','autogpt','AutoGPT - 开源自主 AI 代理','AutoGPT 是开源 AI 代理的先驱项目，让 GPT-4 自主设定目标并使用工具执行任务，开创了自主 AI 代理的新范式。','[\"AutoGPT\", \"自主代理\", \"GPT-4\", \"AI代理\", \"开源AI\", \"任务自动化\"]','2026-06-05 00:00:00.000'),(17,'BabyAGI','BabyAGI 是一个极简但强大的自主 AI 任务管理系统，它通过简短的核心代码（约 140 行）展示了 AI 代理的核心原理：任务创建、优先级排序和执行循环。BabyAGI 使用 LLM 来不断生成新任务、确定优先级并执行最高优先级的任务，形成自驱的任务执行闭环，对理解 AI 代理架构有很高的教育价值。','agent-framework','Free & Open Source','https://github.com/yoheinakajima/babyagi','[\"极简代理架构，核心代码约 140 行\", \"自动任务创建与优先级排序\", \"自驱式任务执行循环\", \"结合向量数据库的记忆存储\", \"易于理解和定制的代码结构\", \"支持多种 LLM 后端\"]','','babyagi','BabyAGI - 极简自主 AI 任务管理系统','BabyAGI 是一个极简自主 AI 任务管理系统，通过约 140 行核心代码展示 AI 代理的核心原理，具有很高的教育价值。','[\"BabyAGI\", \"AI代理\", \"任务管理\", \"自主系统\", \"极简架构\", \"LLM应用\"]','2026-06-05 00:00:00.000'),(18,'Semantic Kernel','Semantic Kernel 是微软开源的轻量级 AI 编排 SDK，支持将 AI 功能无缝集成到传统应用中。它提供了 C#、Python 和 Java 三种语言支持，通过插件架构连接 AI 模型和现有应用代码。Semantic Kernel 是微软企业 AI 战略的核心组件，深度集成 Azure AI 和 Copilot 生态。','agent-framework','Free & Open Source','https://learn.microsoft.com/en-us/semantic-kernel','[\"多语言 SDK 支持（C#、Python、Java）\", \"插件化架构，轻松集成现有代码\", \"与 Azure AI 和 Copilot 深度集成\", \"企业级安全与合规支持\", \"自动函数调用与 AI 规划\", \"丰富的官方文档与示例\"]','','semantic-kernel','Semantic Kernel - 微软开源 AI 编排 SDK','Semantic Kernel 是微软开源的 AI 编排 SDK，支持 C#、Python 和 Java，通过插件架构将 AI 无缝集成到企业应用中。','[\"Semantic Kernel\", \"微软\", \"AI编排\", \"SDK\", \"Azure AI\", \"插件架构\"]','2026-06-05 00:00:00.000'),(19,'Langfuse','Langfuse 是一个开源的 LLM 应用可观测性平台，提供追踪、监控、评估和分析功能。它帮助开发者洞察 LLM 应用的调用链路、Token 用量、延迟和成本，并提供提示词版本管理和 A/B 测试能力。Langfuse 支持 LangChain、LlamaIndex、OpenAI SDK 等主流框架，是 LLM 应用运维的必备工具。','productivity','Open Source, Cloud Hobby Free, Pro $59/mo','https://langfuse.com','[\"LLM 调用链路的全链路追踪\", \"Token 用量与成本实时监控\", \"提示词版本管理与回滚\", \"A/B 测试与效果评估\", \"支持 LangChain、LlamaIndex 等主流框架\", \"开源可自托管部署\"]','','langfuse','Langfuse - 开源 LLM 可观测性平台','Langfuse 是开源的 LLM 应用可观测性平台，提供调用追踪、成本监控和提示词管理功能，是 LLM 应用运维的必备工具。','[\"Langfuse\", \"LLM可观测性\", \"调用追踪\", \"提示词管理\", \"成本监控\", \"开源\"]','2026-06-05 00:00:00.000'),(20,'Weights & Biases','Weights & Biases（W&B）是机器学习实验管理和 MLOps 平台，帮助团队追踪实验、可视化模型性能、管理数据集和自动化 ML 流水线。W&B 已成为 ML 研究团队的标配工具，支持实验记录、超参数搜索、模型注册和协作报告，被 OpenAI、Meta、NVIDIA 等顶级 AI 团队广泛使用。','productivity','Free for individuals, Team $150/mo','https://wandb.ai','[\"实验追踪与自动版本记录\", \"交互式的训练指标可视化面板\", \"超参数自动搜索与优化\", \"模型注册中心与版本管理\", \"团队协作报告与知识共享\", \"ML 流水线自动化与调度\"]','','weights-and-biases','Weights & Biases - ML 实验管理与 MLOps 平台','Weights & Biases 是 ML 实验管理平台，提供实验追踪、模型可视化和流水线自动化功能，被 OpenAI、Meta 等顶级 AI 团队广泛使用。','[\"Weights & Biases\", \"MLOps\", \"实验追踪\", \"模型管理\", \"超参数搜索\", \"ML流水线\"]','2026-06-05 00:00:00.000');
