/*!40000 ALTER TABLE `x_posts` DISABLE KEYS */;
INSERT INTO `x_posts` VALUES (1,'Andrej Karpathy','@karpathy','Just tried the new AI capabilities and I\'m genuinely impressed. The reasoning depth has improved significantly. We\'re entering a new phase of AI development where models don\'t just predict — they think. Exciting times ahead. 🚀',2987,831,152,'https://x.com@karpathy/status/1781071582381','tools','[]','karpathy-post-1','Andrej Karpathy: Just tried the new AI capabilities and I\'m genuinely impress...','Just tried the new AI capabilities and I\'m genuinely impressed. The reasoning depth has improved significantly. We\'re entering a new phase of AI development whe','[\"ai\", \"@karpathy\", \"AI\", \"X\"]','2026-06-08 17:06:59.381','2026-06-08 17:06:59.381'),(2,'Sam Altman','@sama','Hot take: The best AI tool isn\'t the most powerful model — it\'s the one with the best UX. We\'ve been optimizing for benchmarks too long. Time to optimize for human experience.',2568,232,287,'https://x.com@sama/status/1781071611021','open-source','[]','sama-post-2','Sam Altman: Hot take: The best AI tool isn\'t the most powerful model — i...','Hot take: The best AI tool isn\'t the most powerful model — it\'s the one with the best UX. We\'ve been optimizing for benchmarks too long. Time to optimize for hu','[\"gpt\", \"@sama\", \"AI\", \"X\"]','2026-06-09 20:07:01.021','2026-06-09 20:07:01.021'),(3,'Yann LeCun','@ylecun','New paper alert! The latest research on research shows some fascinating results. Key insight: scaling laws still hold, but the curve is shifting. Efficiency gains are outpacing raw size increases. 📈',3400,741,282,'https://x.com@ylecun/status/1781071561699','open-source','[]','ylecun-post-3','Yann LeCun: New paper alert! The latest research on research shows some ...','New paper alert! The latest research on research shows some fascinating results. Key insight: scaling laws still hold, but the curve is shifting. Efficiency gai','[\"research\", \"@ylecun\", \"AI\", \"X\"]','2026-06-07 18:07:01.699','2026-06-07 18:07:01.699'),(4,'Demis Hassabis','@demishassabis','Just shipped a major update. The Gemini integration now supports streaming responses with tool calling. Performance improved 3x. Open source code in thread.',3623,910,308,'https://x.com@demishassabis/status/1781071555375','news','[]','demishassabis-post-4','Demis Hassabis: Just shipped a major update. The Gemini integration now supp...','Just shipped a major update. The Gemini integration now supports streaming responses with tool calling. Performance improved 3x. Open source code in thread.','[\"gemini\", \"@demishassabis\", \"AI\", \"X\"]','2026-06-07 11:07:02.375','2026-06-07 11:07:02.375'),(5,'Jim Fan','@DrJimFan','Hot discussion in the AI community today: Are we over-investing in model size? The trend toward smaller, specialized models + tool use seems more practical for most use cases. What do you think?',334,1010,179,'https://x.com@DrJimFan/status/1781071576050','llm','[]','DrJimFan-post-5','Jim Fan: Hot discussion in the AI community today: Are we over-invest...','Hot discussion in the AI community today: Are we over-investing in model size? The trend toward smaller, specialized models + tool use seems more practical for ','[\"robotics\", \"@DrJimFan\", \"AI\", \"X\"]','2026-06-08 07:07:03.050','2026-06-08 07:07:03.050'),(6,'Simon Willison','@simonw','LLM is evolving so fast. Just 6 months ago this was impossible. Now it\'s becoming commoditized. The pace of AI progress continues to astound me. We\'re living in the future.',2222,940,154,'https://x.com@simonw/status/1781071564729','tools','[]','simonw-post-6','Simon Willison: LLM is evolving so fast. Just 6 months ago this was impossib...','LLM is evolving so fast. Just 6 months ago this was impossible. Now it\'s becoming commoditized. The pace of AI progress continues to astound me. We\'re living in','[\"llm\", \"@simonw\", \"AI\", \"X\"]','2026-06-07 19:07:03.729','2026-06-07 19:07:03.729'),(7,'李沐','@mli','Unpopular opinion: We need more focus on AI safety